import { useState } from "react";
import MedicineSearch from "../components/MedicineSearch";
import DoseResult from "../components/DoseResult";
import AIChatBot from "../components/AIChatBot";
import PatientProfileCard from "../components/PatientProfileCard";
import { Alert, Spinner, Card } from "../components/UI";
import { api } from "../services/api";

export default function CalculatorPage() {
  const [selectedMed, setSelectedMed] = useState(null);
  const [patientProfile, setPatientProfile] = useState(null);
  const [weight, setWeight] = useState("");
  const [ageYears, setAgeYears] = useState("");
  const [ageMonths, setAgeMonths] = useState("");
  const [result, setResult] = useState(null);
  const [error, setError] = useState(null);
  const [loading, setLoading] = useState(false);
  const [showAIChat, setShowAIChat] = useState(false);
  const [aiSuggestion, setAiSuggestion] = useState(null);

  const totalMonths = () => 
    (parseFloat(ageYears) || 0) * 12 + (parseFloat(ageMonths) || 0);

  const handleCalculate = async () => {
    if (!selectedMed || !weight) return;
    setLoading(true);
    setError(null);
    setResult(null);
    try {
      const data = await api.calculateDose({
        medicine_id: selectedMed.id,
        weight_kg: parseFloat(weight),
        age_months: totalMonths() || 1,
        conditions: patientProfile?.conditions || [],
      });
      setResult(data);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const handleAISuggestion = (suggestion) => {
    setAiSuggestion(suggestion);
    if (suggestion.medicine) {
      setSelectedMed(suggestion.medicine);
    }
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-8">
      {/* Page Header */}
      <div className="mb-8">
        <h1 className="text-3xl font-bold text-gray-900 dark:text-white mb-2">
          AI-Powered Dose Calculator
        </h1>
        <p className="text-gray-600 dark:text-gray-400">
          Smart dosing with predictive analytics and clinical intelligence
        </p>
      </div>

      {/* Vertical Layout - Stacked */}
      <div className="flex flex-col gap-6">
        {/* Top Section: Patient Profile & AI Chat - Side by Side */}
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
          <Card className="h-fit">
            <PatientProfileCard onProfileChange={setPatientProfile} />
          </Card>

          <Card className="h-fit">
            <div className="flex items-center justify-between mb-4">
              <h3 className="text-lg font-semibold text-teal-600 dark:text-teal-400">
                AI Assistant
              </h3>
              <button 
                className="px-3 py-1 text-sm border border-gray-300 dark:border-gray-600 rounded-lg hover:bg-gray-100 dark:hover:bg-gray-800 transition"
                onClick={() => setShowAIChat(!showAIChat)}
              >
                {showAIChat ? 'Hide' : 'Chat'}
              </button>
            </div>
            {showAIChat && (
              <AIChatBot 
                patientContext={patientProfile}
                onRecommendation={handleAISuggestion}
              />
            )}
          </Card>
        </div>

        {/* Middle Section: Medication Form */}
        <Card>
          <h2 className="text-xl font-semibold text-gray-900 dark:text-white mb-6">
            Medication Details
          </h2>

          {/* AI Suggestion Banner */}
          {aiSuggestion && (
            <div className="mb-6 p-4 bg-gradient-to-r from-teal-500/10 to-blue-500/10 border border-teal-500 rounded-lg flex items-center justify-between flex-wrap gap-3">
              <div className="flex-1">
                <strong className="block text-teal-600 dark:text-teal-400 mb-1">
                  🤖 AI Suggestion
                </strong>
                <p className="text-sm text-gray-700 dark:text-gray-300">
                  {aiSuggestion.reasoning || 'Based on patient profile'}
                </p>
              </div>
              <button 
                className="px-4 py-2 bg-teal-600 hover:bg-teal-700 text-white text-sm font-semibold rounded-full transition transform hover:scale-105"
                onClick={() => {
                  if (aiSuggestion.medicine) {
                    setSelectedMed(aiSuggestion.medicine);
                  }
                }}
              >
                Apply
              </button>
            </div>
          )}

          {/* Form Grid - 3 columns on desktop */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-6">
            <div className="space-y-2">
              <label className="block text-sm font-semibold text-gray-700 dark:text-gray-300 uppercase tracking-wide">
                Medicine <span className="text-red-500">*</span>
              </label>
              <MedicineSearch
                value={selectedMed}
                onSelect={(med) => {
                  setSelectedMed(med);
                  setResult(null);
                  setError(null);
                }}
                placeholder="Type medicine name..."
              />
            </div>

            <div className="space-y-2">
              <label className="block text-sm font-semibold text-gray-700 dark:text-gray-300 uppercase tracking-wide">
                Weight (kg) <span className="text-red-500">*</span>
              </label>
              <input
                className="w-full px-4 py-2 bg-gray-900 dark:bg-gray-800 border border-gray-700 rounded-lg focus:ring-2 focus:ring-teal-500 focus:border-teal-500 outline-none transition"
                type="number"
                min="0.5"
                step="0.1"
                placeholder="e.g., 70"
                value={weight}
                onChange={(e) => setWeight(e.target.value)}
              />
            </div>

            <div className="space-y-2">
              <label className="block text-sm font-semibold text-gray-700 dark:text-gray-300 uppercase tracking-wide">
                Age
              </label>
              <div className="grid grid-cols-2 gap-3">
                <input
                  className="px-4 py-2 bg-gray-900 dark:bg-gray-800 border border-gray-700 rounded-lg focus:ring-2 focus:ring-teal-500 focus:border-teal-500 outline-none transition"
                  type="number"
                  min="0"
                  placeholder="Years"
                  value={ageYears}
                  onChange={(e) => setAgeYears(e.target.value)}
                />
                <input
                  className="px-4 py-2 bg-gray-900 dark:bg-gray-800 border border-gray-700 rounded-lg focus:ring-2 focus:ring-teal-500 focus:border-teal-500 outline-none transition"
                  type="number"
                  min="0"
                  max="11"
                  placeholder="Months"
                  value={ageMonths}
                  onChange={(e) => setAgeMonths(e.target.value)}
                />
              </div>
            </div>
          </div>

          {/* Calculate Button */}
          <button
            className="w-full py-3 bg-teal-600 hover:bg-teal-700 text-white font-semibold rounded-lg flex items-center justify-center gap-2 transition transform hover:scale-[1.02] disabled:opacity-50 disabled:cursor-not-allowed disabled:hover:scale-100"
            onClick={handleCalculate}
            disabled={!selectedMed || !weight || loading}
          >
            {loading ? <Spinner /> : 'Calculate Safe Dose →'}
          </button>

          {/* Error Message */}
          {error && (
            <div className="mt-4">
              <Alert type="danger">{error}</Alert>
            </div>
          )}
        </Card>

        {/* Bottom Section: Results */}
        {result && (
          <div className="mt-2">
            <DoseResult result={result} />
          </div>
        )}
      </div>
    </div>
  );
}
